class Solution {
public:
    void recoverHeap(vector<int>& nums) {
        unordered_set<int> seen;
        for (auto& num : nums) {
            if (seen.find(num) == seen.end()) {
                seen.insert(num);
            } else {
                nums.erase(remove(nums.begin(), nums.end(), num), nums.end());
            }
        }
        for (int i = nums.size() / 2 - 1; i >= 0; --i) {
            heapify(nums, i);
        }
        return nums;
    }

    void heapify(vector<int>& nums, int i) {
        int smallest = i;
        int left = 2 * i + 1;
        int right = 2 * i + 2;
        if (left < nums.size() && nums[left] < nums[smallest]) {
            smallest = left;
        }
        if (right < nums.size() && nums[right] < nums[smallest]) {
            smallest = right;
        }
        if (smallest != i) {
            swap(nums[i], nums[smallest]);
            heapify(nums, smallest);
        }
    }

    void swap(vector<int>& nums, int i, int j) {
        int temp = nums[i];
        nums[i] = nums[j];
        nums[j] = temp;
    }
};

